<?php
session_start(); $conn=new mysqli('localhost','root','','agroconnect'); $conn->set_charset('utf8mb4'); require_once 'agro_helper.php'; if(!isset($_SESSION['rol'])){header('Location: login.php');exit();}
$rol=$_SESSION['rol']; $eid=intval($_SESSION['empresa_id']??0); $volver=agro_volver_panel(); $sinTabla=!agro_tabla_existe($conn,'historico_actividades')||!agro_tabla_existe($conn,'parcelas'); $mensaje=''; $error='';
if(!$sinTabla && isset($_POST['guardar'])){ $empresa_id=($rol==='superadmin')?intval($_POST['empresa_id']??0):$eid; $parcela_id=intval($_POST['parcela_id']??0); $tipo=$_POST['tipo']??'observacion'; $descripcion=trim($_POST['descripcion']??''); $fecha=$_POST['fecha']?:date('Y-m-d'); $usuario_id=intval($_SESSION['id']??0); if($empresa_id<=0||$descripcion===''){$error='Indica empresa y descripción.';} else {$st=$conn->prepare('INSERT INTO historico_actividades (empresa_id,parcela_id,usuario_id,tipo,descripcion,fecha,fecha_creacion) VALUES (?,?,?,?,?,?,NOW())');$st->bind_param('iiisss',$empresa_id,$parcela_id,$usuario_id,$tipo,$descripcion,$fecha);$mensaje=$st->execute()?'Actividad registrada correctamente.':'No se pudo registrar la actividad.';}}
if(!$sinTabla){$empresas=agro_empresas_visibles($conn); if($rol==='superadmin'){ $parcelas=$conn->query('SELECT id,nombre FROM parcelas ORDER BY nombre ASC'); $hist=$conn->query("SELECT h.*, p.nombre AS parcela, e.nombre AS empresa, u.nombre AS usuario FROM historico_actividades h LEFT JOIN parcelas p ON h.parcela_id=p.id LEFT JOIN empresas e ON h.empresa_id=e.id LEFT JOIN usuarios u ON h.usuario_id=u.id ORDER BY h.fecha DESC, h.id DESC"); } else { $st=$conn->prepare('SELECT id,nombre FROM parcelas WHERE empresa_id=? ORDER BY nombre ASC');$st->bind_param('i',$eid);$st->execute();$parcelas=$st->get_result(); $st2=$conn->prepare("SELECT h.*, p.nombre AS parcela, e.nombre AS empresa, u.nombre AS usuario FROM historico_actividades h LEFT JOIN parcelas p ON h.parcela_id=p.id LEFT JOIN empresas e ON h.empresa_id=e.id LEFT JOIN usuarios u ON h.usuario_id=u.id WHERE h.empresa_id=? ORDER BY h.fecha DESC, h.id DESC");$st2->bind_param('i',$eid);$st2->execute();$hist=$st2->get_result();}}
?>
<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><title>Histórico - AgroConnect</title><link href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.2/dist/css/bootstrap.min.css" rel="stylesheet"><link rel="stylesheet" href="style.css"></head><body class="admin-body"><?php include __DIR__ . '/includes/topbar.php'; ?><div class="admin-container"><div class="dashboard-hero"><div><span class="eyebrow">Históricos</span><h1>Registro de actividades agrícolas</h1><p>Guarda actuaciones, observaciones e incidencias de campo para consultar la evolución de cada explotación.</p></div></div><?php if($sinTabla){?><div class="alert alert-warning">Importa <strong>actualizacion_superadmin.sql</strong> para activar históricos.</div><?php } else { if($mensaje){?><div class="alert alert-success"><?php echo htmlspecialchars($mensaje);?></div><?php } if($error){?><div class="alert alert-danger"><?php echo htmlspecialchars($error);?></div><?php }?><div class="admin-card mb-4"><h3>Nueva actividad</h3><form method="POST" class="row g-3 mt-1"><?php if($rol==='superadmin'){?><div class="col-md-4"><label class="form-label">Empresa</label><select name="empresa_id" class="form-select"><option value="">Seleccionar...</option><?php while($e=$empresas->fetch_assoc()){?><option value="<?php echo $e['id'];?>"><?php echo htmlspecialchars($e['nombre']);?></option><?php }?></select></div><?php }?><div class="col-md-4"><label class="form-label">Parcela</label><select name="parcela_id" class="form-select"><option value="0">General</option><?php while($p=$parcelas->fetch_assoc()){?><option value="<?php echo $p['id'];?>"><?php echo htmlspecialchars($p['nombre']);?></option><?php }?></select></div><div class="col-md-2"><label class="form-label">Tipo</label><select name="tipo" class="form-select"><option value="riego">Riego</option><option value="tratamiento">Tratamiento</option><option value="siembra">Siembra</option><option value="cosecha">Cosecha</option><option value="incidencia">Incidencia</option><option value="observacion">Observación</option></select></div><div class="col-md-2"><label class="form-label">Fecha</label><input type="date" name="fecha" class="form-control" value="<?php echo date('Y-m-d'); ?>"></div><div class="col-md-12"><label class="form-label">Descripción</label><textarea name="descripcion" class="form-control" rows="3" required></textarea></div><div class="col-12"><button name="guardar" class="btn btn-success">Registrar actividad</button></div></form></div><div class="admin-card"><h3>Histórico de actividades</h3><div class="table-responsive"><table class="table"><thead><tr><th>Fecha</th><th>Tipo</th><th>Empresa</th><th>Parcela</th><th>Usuario</th><th>Descripción</th><?php if(in_array($rol,['superadmin','jefe'])){ ?><th>Acciones</th><?php } ?></tr></thead><tbody><?php while($h=$hist->fetch_assoc()){?><tr><td><?php echo htmlspecialchars($h['fecha']);?></td><td><span class="badge bg-success"><?php echo htmlspecialchars($h['tipo']);?></span></td><td><?php echo htmlspecialchars($h['empresa']??'');?></td><td><?php echo htmlspecialchars($h['parcela']??'General');?></td><td><?php echo htmlspecialchars($h['usuario']??'');?></td><td><?php echo nl2br(htmlspecialchars($h['descripcion']));?></td><?php if(in_array($rol,['superadmin','jefe'])){ ?><td><?php echo agro_crud_botones('historico_actividades', $h['id'], 'historico.php'); ?></td><?php } ?></tr><?php }?></tbody></table></div></div><?php }?></div><?php include __DIR__ . '/includes/footer.php'; ?>
</body></html>
